{
    "level": "A2–B1",
    "intro": "W tym temacie poznasz <strong>części składowe</strong> - konstrukcje pomagające <strong>mierzyć rzeczowniki niepoliczalne</strong>: <strong>kawałek, filiżanka, szklanka, kawałek</strong> itp.",
    "rules": [
        {
            "label": "Kawałek",
            "color": "emerald",
            "text": "<strong>Kawałek / część</strong> czegoś:",
            "example": "kawałek ciasta, kawałek rada"
        },
        {
            "label": "Filiżanka",
            "color": "blue",
            "text": "<strong>Filiżanka/szklanka</strong> napoju:",
            "example": "filiżanka kawy, filiżanka herbaty"
        },
        {
            "label": "Butelka",
            "color": "amber",
            "text": "<strong>Butelka</strong> płyn:",
            "example": "butelka wody, butelka mleka"
        }
    ]
}

{
    "title": "1. Czym są cząstki?",
    "intro": "Cząsteczki to sposoby mierzenia rzeczowników niepoliczalnych:",
    "items": [
        {
            "label": "Pojemniki",
            "title": "Naczynia / Pojemniki",
            "subtitle": "kubek, szklanka, butelka — miara płyny"
        },
        {
            "label": "Porcje",
            "title": "Porcje/Części",
            "subtitle": "kawałek, kromka, bochenek — wymiary jedzenia"
        },
        {
            "label": "Jednostki",
            "title": "Miara jednostki",
            "subtitle": "kilogram, litr, funt — masa i objętość"
        }
    ]
}

{
