{
    "title": "4. Porcje jedzenia - kromka, bochenek, batonik",
    "sections": [
        {
            "label": "Kromka - kromka",
            "color": "emerald",
            "description": "<strong>Kawałek</strong> - na kromki.",
            "examples": [
                {
                    "en": "kromka chleba",
                    "ua": "kromka chleba"
                },
                {
                    "en": "kromka chleba kromka sera</strong> — na bochenki.",
                    "ua": "шматок піци"
                },
                {
                    "en": "a slice of cheese",
                    "ua": "скибка сиру"
                },
                {
                    "en": "a slice of cake",
                    "ua": "шматок торта"
                }
            ]
        },
        {
            "label": "A loaf of — буханка",
            "color": "amber",
            "description": "<strong>A loaf of</strong> — для буханок.",
            "examples": [
                {
                    "en": "bochenek chleba",
                    "ua": "buhanka"
                },
                {
                    "en": "dwa bochenki chleba",
                    "ua": "dwa bochenki chleba"
                }
