        },
        {
            "label": "batonik — dachówka/bar",
            "color": "rose",
            "description": "<strong>Pasek - dla płytek/pasków. Pojemniki: pudełko, puszka, słoik",
            "examples": [
                {
                    "en": "a bar of chocolate",
                    "ua": "плитка шоколаду"
                },
                {
                    "en": "a bar of soap",
                    "ua": "шматок мила"
                }
            ]
        }
    ]
}

{
    "title": "5. Контейнери — box, can, jar",
