        {
            "label": "A box of — коробка",
            "color": "purple",
            "description": "<strong>A box of</strong> — для речей у коробці.",
            "examples": [
                {
                    "en": "a box of chocolates",
                    "ua": "коробка цукерок"
                },
                {
                    "en": "a box of cereal",
                    "ua": "pudełko suchej żywności śniadaniowej"
                },
                {
                    "en": "pudełko chusteczek",
                    "ua": "pudełko serwetek"
                }
            ]
        },
        {
            "label": "Puszka — puszka (puszka)",
            "color": "sky",
            "description": "<strong>Puszka</strong> — w puszkach jedzenie.",
            "examples": [
                {
                    "en": "puszka zupy",
                    "ua": "puszka zupy"
                },
                {
                    "en": "puszka fasoli",
                    "ua": "puszka fasoli"
                },
                {
                    "en": "puszka napoju gazowanego",
                    "ua": "puszka napój gazowany"
                }
