        },
        {
            "label": "Słoik — słoik (szkło)",
            "color": "emerald",
            "description": "<strong>Słoik</strong> – na rzeczy w szklanym słoju.",
            "examples": [
                {
                    "en": "słoik dżemu",
                    "ua": "słoik dżemu"
                },
                {
                    "en": "słoik miód",
                    "ua": "słoik miodu"
                },
                {
                    "en": "słoik ogórków kiszonych",
                    "ua": "słoik ogórków kiszonych"
                }
            ]
        }
    ]
}

{
    "title": "6. Torby i torby — torba, paczka, karton",
    "sections": [
        {
            "label": "Torba — torba ",
            "color": "amber",
            "description": "<strong>Torba</strong> — na rzeczy w torbie lub torbie.",
            "examples": [
                {
                    "en": "worek cukru",
                    "ua": "worek cukru cukier"
                },
                {
                    "en": "worek ryżu</strong> — na rzeczy w paczce.",
                    "ua": "пакет борошна"
                },
                {
                    "en": "a bag of rice",
                    "ua": "мішок рису"
                },
                {
                    "en": "a bag of potatoes",
                    "ua": "мішок картоплі"
                }
            ]
        },
        {
            "label": "A packet of — пачка",
            "color": "rose",
            "description": "<strong>A packet of</strong> — для речей у пачці.",
            "examples": [
                {
                    "en": "paczka chipsów",
                    "ua": "paczka chipsów"
                },
                {
                    "en": "paczka ciastek",
                    "ua": "paczka ciastka"
                },
                {
                    "en": "paczka papierosów",
                    "ua": "paczka papierosów"
                }
            ]
        },
        {
            "label": "Karton - pudełko kartonowe",
            "color": "sky",
            "description": "<strong>Karton</strong> - na płyny w opakowaniach kartonowych.",
            "examples": [
                {
                    "en": "karton mleka",
                    "ua": "karton mleka"
                },
                {
                    "en": "karton soku",
                    "ua": "karton soku"
                },
                {
                    "en": "karton jajek",
                    "ua": "taca jaja"
                }
            ]
