    ]
}

{
    "title": "7. Jednostki miary — kilo, litr, funt jabłek",
    "sections": [
        {
            "label": "A kilo of — кілограм",
            "color": "purple",
            "description": "<strong>A kilo of</strong> — для ваги в кілограмах.",
            "examples": [
                {
                    "en": "a kilo of sugar",
                    "ua": "кілограм цукру"
                },
                {
                    "en": "a kilo of apples",
                    "ua": "кілограм яблук"
                },
                {
                    "en": "dwa kilogramy ziemniaków",
                    "ua": "dwa kilogramy ziemniaków"
                }
            ]
        },
        {
            "label": "Litr — litr",
            "color": "blue",
            "description": "<strong>Litr</strong> — dla objętości w litry.",
            "examples": [
                {
                    "en": "litr wody",
                    "ua": "litr wody"
                },
                {
                    "en": "litr mleka",
                    "ua": "litr mleka"
                },
                {
                    "en": "dwa litry soku",
                    "ua": "dwa litry soku sok"
                }
            ]
        },
        {
            "label": "Funt — funt",
            "color": "emerald",
            "description": "<strong>Funt</strong> — w przypadku wagi w funtach (system brytyjski. Inne przydatne części",
            "examples": [
                {
                    "en": "a pound of butter",
                    "ua": "фунт масла"
                },
                {
                    "en": "a pound of coffee",
                    "ua": "фунт кави"
                }
            ],
            "note": "📌 1 pound = приблизно 450 грамів."
        }
    ]
}

{
    "title": "8. Інші корисні партитиви",
    "sections": [
        {
            "label": "Miska - miska",
            "color": "sky",
            "description": "<strong>Miska</strong> - do jedzenia w miska.",
            "examples": [
                {
                    "en": "miska zupy",
                    "ua": "miska zupy"
                },
                {
                    "en": "miska płatków",
                    "ua": "miska płatków"
                },
                {
                    "en": "miska ryżu",
                    "ua": "miska płatków ryż"
