{
    "title": "9. Порівняльна таблиця партитивів",
    "intro": "Główne części i ich zastosowanie:",
    "rows": [
        {
            "en": "Kawałek",
            "ua": "Schát / część",
            "note": "ciasto, chleb, porady, informacje, meble"
        },
        {
            "en": "Kubek z",
            "ua": "Filiżanka",
            "note": "kawy, herbaty, gorącej czekolady (gorące napoje)"
        },
        {
            "en": "Kieliszek",
            "ua": "Szklanka",
            "note": "wody, soku, mleka, wina (zimnego napoje)"
        },
        {
            "en": "Butelka",
            "ua": "Butelka",
            "note": "woda, mleko, wino, piwo"
        },
        {
            "en": "Kawałek",
            "ua": "Kawałek/sztuka",
            "note": "chleb, pizza, ser, ciasto"
        },
        {
            "en": "Bochenek",
            "ua": "Buhanka",
            "note": "chleb (bochenki w liczbie mnogiej)"
