    "warning": "📌 Części składowe są zawsze używane z <strong>of</strong> + rzeczownikiem niepoliczalnym!"
}

{
    "title": "10. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Zapomnij o po cząsteczku.",
            "wrong": "Potrzebuję porady.",
            "right": "​​​​ <span class="font-mono">Potrzebuję kawałka rada.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Nieprawidłowa cząstkowa liczba mnoga.",
            "wrong": "dwa bochenki chleba",
            "right": "​​​​ <span class="font-mono">dwa bochenki chleba</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Źle wybór częściowy.",
            "wrong": "kawałek mleka (niepoprawny)",
            "right": "​​​​​​​​​​ / Potrzebuję trochę wody.</span>"
        },
        {
            "label": "Помилка 4",
            "color": "purple",
            "title": "Артикль a з незлічуваними.",
            "wrong": "I need a water.",
            "right": "✅ <span class="font-mono">I need a glass of water. / I need some water.</span>"
        }
    ]
}

{
    "title": "12. Ćwicz",
    "select_title": "Ćwiczenie 1. Wybierz właściwy człon cząstkowy",
    "select_intro": "Wybierz poprawną konstrukcję dla każdego rzeczownika.",
    "selects": [
        {
            "label": "Potrzebuję ___ porady. (kawałek / filiżanka)",
            "prompt": "Jaka część?"
        },
        {
            "label": "Czy mogę dostać ___ wodę? (kawałek/szklanka)",
            "prompt": "Jaka część?"
        },
        {
            "label": "Kupiła ___ chleb. (bochenek / butelka)",
            "prompt": "Jaka część?"
        },
        {
            "label": "Chcę ___ czekolady. (kawałek/pasek) informacji.",
            "prompt": "Який партитив?"
        }
    ],
    "options": [
        "Перший варіант",
        "Другий варіант"
    ],
    "input_title": "Вправа 2. Заповни пропуски",
    "input_intro": "Напиши правильний партитив (з of).",
    "inputs": [
        {
            "before": "I need ___ information.",
            "after": " →"
        },
        {
            "before": "Czy mogę wypić ___ kawę?",
            "after": " →[[CODX_SEG_13]]]Kupiła ___ jam."
        },
        {
            "before": "She bought ___ jam.",
            "after": " →"
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Korekcja błędów",
    "rephrase_intro": "Znajdź i popraw błąd za pomocą częściowej.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "Potrzebuję rada.",
            "example_target": "Potrzebuję rady. / Potrzebuję porady."
        },
        {
            "original": "1. Czy mogę napić się kawy?",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "2. Kupiła dwa bochenki chleba.",
            "placeholder": "Popraw błąd"
        }
    ]
}

